<?php
$notice=''; $error='';
$schema=function_exists('omurga_theme_settings_definitions') ? omurga_theme_settings_definitions('topluluk-v1') : [];
$values=function_exists('omurga_theme_settings_values') ? omurga_theme_settings_values('topluluk-v1') : setting_json('theme_settings_topluluk-v1', []);
function tv1_panel_sanitize(array $input, array $schema): array { $out=[]; foreach($schema as $key=>$field){ if(!is_array($field)) continue; $safe=preg_replace('/[^a-zA-Z0-9_\-]/','',(string)$key); if($safe==='') continue; $type=(string)($field['type'] ?? 'text'); if($type==='checkbox'){ $out[$safe]=!empty($input[$safe])?'1':'0'; continue; } $value=$input[$safe] ?? ($field['default'] ?? ''); if(is_array($value)) $value=implode(',',array_map('strval',$value)); $value=trim((string)$value); if($type==='color' && !preg_match('/^#[0-9a-fA-F]{6}$/',$value)) $value=(string)($field['default'] ?? '#0d2240'); if($type==='url') $value=filter_var($value,FILTER_SANITIZE_URL); $out[$safe]=$value; } return $out; }
try{ if(($_SERVER['REQUEST_METHOD'] ?? '')==='POST'){ verify_csrf(); $action=(string)($_POST['action'] ?? ''); if($action==='save_settings'){ $data=tv1_panel_sanitize(is_array($_POST['settings'] ?? null)?$_POST['settings']:[],$schema); update_theme_settings($data,'topluluk-v1'); $notice='Topluluk V1 tema ayarları kaydedildi.'; } elseif($action==='import_demo'){ $r=tv1_demo_import(false); $notice=(string)($r['message'] ?? 'Demo yüklendi.'); if(isset($r['created'])) $notice.=' Oluşturulan yeni içerik: '.(int)$r['created'].'.'; } elseif($action==='reset_visual'){ $r=tv1_demo_import(true); $notice=(string)($r['message'] ?? 'Görünüm sıfırlandı.'); } $values=function_exists('omurga_theme_settings_values') ? omurga_theme_settings_values('topluluk-v1') : setting_json('theme_settings_topluluk-v1', []); } } catch(Throwable $e){ if(function_exists('omurga_write_error')) omurga_write_error($e); $error=$e->getMessage(); }
$installedAt=setting('topluluk_v1_demo_installed_at',''); $activeTheme=function_exists('omurga_active_theme') ? omurga_active_theme() : setting('active_theme','');
?>
